@page "/patients"
@attribute [Authorize]
@rendermode InteractiveServer
@inject ApplicationDbContext Db

<PageTitle>Patients</PageTitle>

<h2 class="mb-3">Patients</h2>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search pets by name, species, or owner..."
               @bind="searchTerm" @bind:event="oninput" @bind:after="Search" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick="ToggleNewForm">
            @(showNewForm ? "Cancel" : "Register New Pet")
        </button>
    </div>
</div>

@if (showNewForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Register New Pet</h5>
            <div class="row mb-3">
                <div class="col-12">
                    <label class="form-label">Owner (type to search or enter new)</label>
                    <input type="text" class="form-control" placeholder="Search owner by name..."
                           @bind="ownerSearch" @bind:event="oninput" @bind:after="SearchOwners" />
                    @if (matchingOwners.Any())
                    {
                        <ul class="list-group mt-1" style="max-height:150px;overflow-y:auto;">
                            @foreach (var o in matchingOwners)
                            {
                                <li class="list-group-item list-group-item-action" style="cursor:pointer"
                                    @onclick="() => SelectOwner(o)">
                                    @o.FullName — @o.Email
                                </li>
                            }
                        </ul>
                    }
                </div>
            </div>

            @if (selectedOwner == null)
            {
                <h6>New Owner Details</h6>
                <div class="row mb-2">
                    <div class="col-md-3">
                        <input class="form-control" placeholder="First Name" @bind="newOwnerFirst" />
                    </div>
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Last Name" @bind="newOwnerLast" />
                    </div>
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Phone" @bind="newOwnerPhone" />
                    </div>
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Email" @bind="newOwnerEmail" />
                    </div>
                </div>
            }
            else
            {
                <div class="alert alert-info">Selected owner: <strong>@selectedOwner.FullName</strong>
                    <button class="btn btn-sm btn-link" @onclick="ClearOwner">Change</button>
                </div>
            }

            <h6>Pet Details</h6>
            <div class="row mb-2">
                <div class="col-md-3">
                    <input class="form-control" placeholder="Pet Name *" @bind="newPetName" />
                </div>
                <div class="col-md-2">
                    <input class="form-control" placeholder="Species *" @bind="newPetSpecies" />
                </div>
                <div class="col-md-2">
                    <input class="form-control" placeholder="Breed" @bind="newPetBreed" />
                </div>
                <div class="col-md-2">
                    <input type="date" class="form-control" @bind="newPetDob" />
                </div>
                <div class="col-md-1">
                    <input type="number" step="0.1" class="form-control" placeholder="Kg" @bind="newPetWeight" />
                </div>
                <div class="col-md-2">
                    <input class="form-control" placeholder="Microchip ID" @bind="newPetMicrochip" />
