@code {
    private List<Pet> pets = new();
    private bool loading = true;
    private string searchTerm = "";

    private bool showNewForm;
    private string ownerSearch = "";
    private List<Owner> matchingOwners = new();
    private Owner? selectedOwner;

    private string newOwnerFirst = "", newOwnerLast = "", newOwnerPhone = "", newOwnerEmail = "";
    private string newPetName = "", newPetSpecies = "", newPetBreed = "", newPetMicrochip = "";
    private DateTime? newPetDob;
    private decimal? newPetWeight;
    private string formError = "";
    private bool saving;

    protected override async Task OnInitializedAsync()
    {
        await LoadPets();
    }

    private async Task LoadPets()
    {
        loading = true;
        var query = Db.Pets.Include(p => p.Owner).AsQueryable();
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.ToLower();
            query = query.Where(p => p.Name.ToLower().Contains(term)
                || p.Species.ToLower().Contains(term)
                || p.Owner.FirstName.ToLower().Contains(term)
                || p.Owner.LastName.ToLower().Contains(term));
        }
        pets = await query.OrderBy(p => p.Name).ToListAsync();
        loading = false;
    }

    private async Task Search() => await LoadPets();

    private void ToggleNewForm()
    {
        showNewForm = !showNewForm;
        formError = "";
    }

    private async Task SearchOwners()
    {
        if (ownerSearch.Length < 2) { matchingOwners = new(); return; }
        var term = ownerSearch.ToLower();
        matchingOwners = await Db.Owners
            .Where(o => o.FirstName.ToLower().Contains(term) || o.LastName.ToLower().Contains(term))
            .Take(10).ToListAsync();
    }

    private void SelectOwner(Owner o)
    {
        selectedOwner = o;
        matchingOwners = new();
        ownerSearch = o.FullName;
    }

    private void ClearOwner()
    {
        selectedOwner = null;
        ownerSearch = "";
    }

    private async Task SaveNewPet()
    {
        formError = "";
        if (string.IsNullOrWhiteSpace(newPetName) || string.IsNullOrWhiteSpace(newPetSpecies))
        {
            formError = "Pet name and species are required.";
            return;
        }

        saving = true;
        try
        {
            Owner owner;
            if (selectedOwner != null)
            {
                owner = selectedOwner;
            }
            else
            {
                if (string.IsNullOrWhiteSpace(newOwnerFirst) || string.IsNullOrWhiteSpace(newOwnerLast))
                {
                    formError = "Owner first and last name are required.";
                    saving = false;
                    return;
                }
                owner = new Owner
                {
                    FirstName = newOwnerFirst,
                    LastName = newOwnerLast,
                    Phone = string.IsNullOrWhiteSpace(newOwnerPhone) ? null : newOwnerPhone,
                    Email = string.IsNullOrWhiteSpace(newOwnerEmail) ? null : newOwnerEmail
                };
                Db.Owners.Add(owner);
            }

            var pet = new Pet
            {
                Name = newPetName,
                Species = newPetSpecies,
                Breed = string.IsNullOrWhiteSpace(newPetBreed) ? null : newPetBreed,
                DateOfBirth = newPetDob.HasValue ? DateOnly.FromDateTime(newPetDob.Value) : null,
                WeightKg = newPetWeight,
                MicrochipId = string.IsNullOrWhiteSpace(newPetMicrochip) ? null : newPetMicrochip,
                Owner = owner
            };
            Db.Pets.Add(pet);
            await Db.SaveChangesAsync();

            showNewForm = false;
            newPetName = newPetSpecies = newPetBreed = newPetMicrochip = "";
            newOwnerFirst = newOwnerLast = newOwnerPhone = newOwnerEmail = "";
            newPetDob = null;
            newPetWeight = null;
            selectedOwner = null;
            ownerSearch = "";
            await LoadPets();
        }
        catch (Exception ex)
        {
            formError = $"Error saving: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }
}

