        @if (availableSlots.Any() && selectedDate.HasValue)
        {
            <div class="mt-3">
                <h6>Available slots on @selectedDate.Value.ToString("MMM dd, yyyy"):</h6>
                <div class="d-flex flex-wrap gap-1">
                    @foreach (var slot in availableSlots)
                    {
                        var t = TimeOnly.FromTimeSpan(slot);
                        <span class="badge bg-success" style="cursor:pointer"
                              @onclick="() => selectedTime = slot.ToString(@"hh\:mm")">@t.ToString("hh:mm tt")</span>
                    }
                </div>
            </div>
        }

        @if (!string.IsNullOrEmpty(error))
        {
            <div class="alert alert-danger mt-3">@error</div>
        }

        <button class="btn btn-primary mt-3" @onclick="Save" disabled="@saving">
            @(saving ? "Saving..." : "Create Appointment")
        </button>
    </div>
</div>

@code {
    private string petSearch = "";
    private List<Pet> matchingPets = new();
    private Pet? selectedPet;
    private DateTime? selectedDate;
    private string selectedTime = "";
    private int duration = 30;
    private string reason = "", veterinarian = "", error = "";
    private bool saving;
    private List<TimeSpan> availableSlots = new();

    private async Task SearchPets()
    {
        if (petSearch.Length < 2) { matchingPets = new(); return; }
        var term = petSearch.ToLower();
        matchingPets = await Db.Pets.Include(p => p.Owner)
            .Where(p => p.Name.ToLower().Contains(term))
            .Take(10).ToListAsync();
    }

    private void SelectPet(Pet p)
    {
        selectedPet = p;
        matchingPets = new();
        petSearch = p.Name;
    }

    private async Task LoadAvailability()
    {
        availableSlots = new();
        if (!selectedDate.HasValue) return;

        var dayStart = selectedDate.Value;
        var dayEnd = selectedDate.Value.AddDays(1);
        var existing = await Db.Appointments
            .Where(a => a.StartTime >= dayStart && a.StartTime < dayEnd && a.Status != AppointmentStatus.Cancelled)
            .Select(a => new { a.StartTime, a.EndTime })
            .ToListAsync();

        for (var t = new TimeSpan(8, 0, 0); t < new TimeSpan(18, 0, 0); t += TimeSpan.FromMinutes(30))
        {
            var slotStart = selectedDate.Value + t;
            var slotEnd = slotStart.AddMinutes(30);
            bool isFree = !existing.Any(e => e.StartTime < slotEnd && e.EndTime > slotStart);
            if (isFree) availableSlots.Add(t);
        }
    }

    private async Task Save()
    {
        error = "";
        if (selectedPet == null) { error = "Please select a pet."; return; }
        if (!selectedDate.HasValue || string.IsNullOrEmpty(selectedTime)) { error = "Please select date and time."; return; }
        if (string.IsNullOrWhiteSpace(reason)) { error = "Reason is required."; return; }

        if (!TimeSpan.TryParse(selectedTime, out var time))
        {
            error = "Invalid time selected.";
            return;
        }

        saving = true;
        try
        {
            var startTime = selectedDate.Value + time;
            var appt = new Appointment
            {
                StartTime = startTime,
                EndTime = startTime.AddMinutes(duration),
                Reason = reason,
                Veterinarian = string.IsNullOrWhiteSpace(veterinarian) ? null : veterinarian,
                PetId = selectedPet.Id,
                Status = AppointmentStatus.Scheduled
            };
            Db.Appointments.Add(appt);
            await Db.SaveChangesAsync();
            Nav.NavigateTo("/appointments");
        }
        catch (Exception ex) { error = $"Error: {ex.Message}"; }
        finally { saving = false; }
    }
}

