@code {
    [Parameter] public int Id { get; set; }

    private Invoice? invoice;
    private bool loading = true;
    private string message = "";

    private string newLineDesc = "", lineError = "";
    private int newLineQty = 1;
    private decimal newLinePrice;

    private decimal payAmount;
    private PaymentMethod payMethod = PaymentMethod.Cash;
    private string payReference = "", payError = "";

    protected override async Task OnInitializedAsync()
    {
        invoice = await Db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == Id);
        loading = false;
    }

    private async Task AddLineItem()
    {
        lineError = "";
        if (string.IsNullOrWhiteSpace(newLineDesc)) { lineError = "Description required."; return; }
        if (newLineQty < 1) { lineError = "Quantity must be at least 1."; return; }

        var item = new InvoiceLineItem
        {
            Description = newLineDesc,
            Quantity = newLineQty,
            UnitPrice = newLinePrice,
            InvoiceId = invoice!.Id
        };
        Db.InvoiceLineItems.Add(item);
        await Db.SaveChangesAsync();
        invoice.LineItems.Add(item);
        newLineDesc = "";
        newLineQty = 1;
        newLinePrice = 0;
    }

    private async Task RemoveLineItem(InvoiceLineItem item)
    {
        Db.InvoiceLineItems.Remove(item);
        await Db.SaveChangesAsync();
        invoice!.LineItems.Remove(item);
    }

    private async Task IssueInvoice()
    {
        invoice!.Status = InvoiceStatus.Issued;
        await Db.SaveChangesAsync();
        message = "Invoice issued successfully.";
    }

    private async Task RecordPayment()
    {
        payError = "";
        if (payAmount <= 0) { payError = "Amount must be greater than 0."; return; }

        var payment = new Payment
        {
            Amount = payAmount,
            Method = payMethod,
            Reference = string.IsNullOrWhiteSpace(payReference) ? null : payReference,
            InvoiceId = invoice!.Id,
            PaidAt = DateTime.UtcNow
        };
        Db.Payments.Add(payment);

        if (invoice.AmountPaid + payAmount >= invoice.Total)
            invoice.Status = InvoiceStatus.Paid;

        await Db.SaveChangesAsync();
        invoice.Payments.Add(payment);
        payAmount = 0;
        payReference = "";
        message = "Payment recorded.";
    }

    private string GetStatusBadge(InvoiceStatus s) => s switch
    {
        InvoiceStatus.Draft => "bg-secondary",
        InvoiceStatus.Issued => "bg-primary",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        _ => "bg-secondary"
    };
}

