@code {
    private DateOnly weekStart;
    private DateOnly weekEnd;
    private List<DateOnly> days = new();
    private List<TimeSpan> slots = new();
    private List<Appointment> appointments = new();
    private bool loading = true;

    private bool showCreateForm, showEditForm, saving;
    private DateTime? selectedSlotTime;
    private Appointment? selectedAppointment;
    private DateTime? rescheduleTime;

    private string petSearch = "", newReason = "", newVet = "", formError = "", editError = "";
    private int newDuration = 30;
    private List<Pet> matchingPets = new();
    private Pet? selectedPet;

    protected override async Task OnInitializedAsync()
    {
        InitSlots();
        SetWeek(DateOnly.FromDateTime(DateTime.Today));
        await LoadAppointments();
    }

    private void InitSlots()
    {
        slots = new();
        for (var t = new TimeSpan(8, 0, 0); t < new TimeSpan(18, 0, 0); t += TimeSpan.FromMinutes(30))
            slots.Add(t);
    }

    private void SetWeek(DateOnly date)
    {
        var dow = date.DayOfWeek;
        int diff = dow == DayOfWeek.Sunday ? -6 : (int)DayOfWeek.Monday - (int)dow;
        weekStart = date.AddDays(diff);
        weekEnd = weekStart.AddDays(5); // Mon-Sat
        days = Enumerable.Range(0, 6).Select(i => weekStart.AddDays(i)).ToList();
    }

    private async Task LoadAppointments()
    {
        loading = true;
        var start = weekStart.ToDateTime(TimeOnly.MinValue);
        var end = weekEnd.AddDays(1).ToDateTime(TimeOnly.MinValue);
        appointments = await Db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= start && a.StartTime < end)
            .ToListAsync();
        loading = false;
    }

    private Appointment? GetAppointment(DateTime slotTime)
    {
        return appointments.FirstOrDefault(a => a.StartTime <= slotTime && a.EndTime > slotTime);
    }

    private async Task PrevWeek() { SetWeek(weekStart.AddDays(-7)); await LoadAppointments(); }
    private async Task NextWeek() { SetWeek(weekStart.AddDays(7)); await LoadAppointments(); }
    private async Task GoToday() { SetWeek(DateOnly.FromDateTime(DateTime.Today)); await LoadAppointments(); }

    private void SelectSlot(DateTime slotTime)
    {
        selectedSlotTime = slotTime;
        showCreateForm = true;
        showEditForm = false;
        formError = "";
        petSearch = "";
        matchingPets = new();
        selectedPet = null;
        newReason = "";
        newVet = "";
        newDuration = 30;
    }

    private void SelectAppointment(Appointment appt)
    {
        selectedAppointment = appt;
        rescheduleTime = appt.StartTime;
        showEditForm = true;
        showCreateForm = false;
        editError = "";
    }

    private async Task SearchPets()
    {
        if (petSearch.Length < 2) { matchingPets = new(); return; }
        var term = petSearch.ToLower();
        matchingPets = await Db.Pets.Include(p => p.Owner)
            .Where(p => p.Name.ToLower().Contains(term))
            .Take(10).ToListAsync();
    }

    private void SelectPet(Pet p)
    {
        selectedPet = p;
        matchingPets = new();
        petSearch = p.Name;
    }

    private async Task CreateAppointment()
    {
        formError = "";
        if (selectedPet == null) { formError = "Please select a pet."; return; }
        if (string.IsNullOrWhiteSpace(newReason)) { formError = "Reason is required."; return; }
        saving = true;
        try
        {
            var appt = new Appointment
            {
                StartTime = selectedSlotTime!.Value,
                EndTime = selectedSlotTime.Value.AddMinutes(newDuration),
                Reason = newReason,
                Veterinarian = string.IsNullOrWhiteSpace(newVet) ? null : newVet,
                PetId = selectedPet.Id,
                Status = AppointmentStatus.Scheduled
            };
            Db.Appointments.Add(appt);
            await Db.SaveChangesAsync();
            showCreateForm = false;
            await LoadAppointments();
        }
        catch (Exception ex) { formError = $"Error: {ex.Message}"; }
        finally { saving = false; }
    }

    private async Task Reschedule()
    {
        editError = "";
        if (rescheduleTime == null) { editError = "Select a new time."; return; }
        saving = true;
        try
        {
            var duration = selectedAppointment!.EndTime - selectedAppointment.StartTime;
            selectedAppointment.StartTime = rescheduleTime.Value;
            selectedAppointment.EndTime = rescheduleTime.Value + duration;
            await Db.SaveChangesAsync();
            showEditForm = false;
            await LoadAppointments();
        }
        catch (Exception ex) { editError = $"Error: {ex.Message}"; }
        finally { saving = false; }
    }

    private async Task CancelAppointment()
    {
        selectedAppointment!.Status = AppointmentStatus.Cancelled;
        await Db.SaveChangesAsync();
        showEditForm = false;
        await LoadAppointments();
    }

    private async Task CompleteAppointment()
    {
        selectedAppointment!.Status = AppointmentStatus.Completed;
        await Db.SaveChangesAsync();
        showEditForm = false;
        await LoadAppointments();
    }
}

