@code {
    private List<Invoice> invoices = new();
    private bool loading = true;
    private string statusFilter = "";
    private DateTime? dateFrom, dateTo;

    protected override async Task OnInitializedAsync() => await LoadInvoices();

    private async Task LoadInvoices()
    {
        loading = true;
        var query = Db.Invoices.Include(i => i.Owner).Include(i => i.LineItems).Include(i => i.Payments).AsQueryable();

        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<InvoiceStatus>(statusFilter, out var st))
            query = query.Where(i => i.Status == st);
        if (dateFrom.HasValue)
            query = query.Where(i => i.IssuedDate >= dateFrom.Value);
        if (dateTo.HasValue)
            query = query.Where(i => i.IssuedDate <= dateTo.Value);

        invoices = await query.OrderByDescending(i => i.IssuedDate).ToListAsync();
        loading = false;
    }

    private string GetStatusBadge(InvoiceStatus s) => s switch
    {
        InvoiceStatus.Draft => "bg-secondary",
        InvoiceStatus.Issued => "bg-primary",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        _ => "bg-secondary"
    };
}

