+        if (string.IsNullOrWhiteSpace(newPetName) || string.IsNullOrWhiteSpace(newPetSpecies))
+        {
+            formError = "Pet name and species are required.";
+            return;
+        }
+
+        saving = true;
+        try
+        {
+            Owner owner;
+            if (selectedOwner != null)
+            {
+                owner = selectedOwner;
+            }
+            else
+            {
+                if (string.IsNullOrWhiteSpace(newOwnerFirst) || string.IsNullOrWhiteSpace(newOwnerLast))
+                {
+                    formError = "Owner first and last name are required.";
+                    saving = false;
+                    return;
+                }
+                owner = new Owner
+                {
+                    FirstName = newOwnerFirst,
+                    LastName = newOwnerLast,
+                    Phone = string.IsNullOrWhiteSpace(newOwnerPhone) ? null : newOwnerPhone,
+                    Email = string.IsNullOrWhiteSpace(newOwnerEmail) ? null : newOwnerEmail
+                };
+                Db.Owners.Add(owner);
+            }
+
+            var pet = new Pet
+            {
+                Name = newPetName,
+                Species = newPetSpecies,
+                Breed = string.IsNullOrWhiteSpace(newPetBreed) ? null : newPetBreed,
+                DateOfBirth = newPetDob.HasValue ? DateOnly.FromDateTime(newPetDob.Value) : null,
+                WeightKg = newPetWeight,
+                MicrochipId = string.IsNullOrWhiteSpace(newPetMicrochip) ? null : newPetMicrochip,
+                Owner = owner
+            };
+            Db.Pets.Add(pet);
+            await Db.SaveChangesAsync();
+
+            showNewForm = false;
+            newPetName = newPetSpecies = newPetBreed = newPetMicrochip = "";
+            newOwnerFirst = newOwnerLast = newOwnerPhone = newOwnerEmail = "";
+            newPetDob = null;
+            newPetWeight = null;
+            selectedOwner = null;
+            ownerSearch = "";
+            await LoadPets();
+        }
+        catch (Exception ex)
+        {
+            formError = $"Error saving: {ex.Message}";
+        }
+        finally
+        {
+            saving = false;
+        }
+    }
+}
+

