+@page "/patients/{Id:int}"
+@attribute [Authorize]
+@rendermode InteractiveServer
+@inject ApplicationDbContext Db
+@inject NavigationManager Nav
+
+<PageTitle>Edit Patient</PageTitle>
+
+@if (loading)
+{
+    <p><em>Loading...</em></p>
+}
+else if (pet == null)
+{
+    <p class="text-danger">Patient not found.</p>
+}
+else
+{
+    <h2 class="mb-3">Edit Patient: @pet.Name</h2>
+
+    <div class="card mb-4">
+        <div class="card-body">
+            <h5 class="card-title">Pet Details</h5>
+            <div class="row mb-2">
+                <div class="col-md-3">
+                    <label class="form-label">Name</label>
+                    <input class="form-control" @bind="pet.Name" />
