+                <div class="col-md-2">
+                    <label class="form-label">Species</label>
+                    <input class="form-control" @bind="pet.Species" />
+                </div>
+                <div class="col-md-2">
+                    <label class="form-label">Breed</label>
+                    <input class="form-control" @bind="pet.Breed" />
+                </div>
+                <div class="col-md-2">
+                    <label class="form-label">Date of Birth</label>
+                    <input type="date" class="form-control" @bind="petDob" />
+                </div>
+                <div class="col-md-1">
+                    <label class="form-label">Weight (kg)</label>
+                    <input type="number" step="0.1" class="form-control" @bind="pet.WeightKg" />
+                </div>
+                <div class="col-md-2">
+                    <label class="form-label">Microchip ID</label>
+                    <input class="form-control" @bind="pet.MicrochipId" />
+                </div>
+            </div>
+
+            <h5 class="mt-3">Owner Details</h5>
+            <div class="row mb-2">
+                <div class="col-md-3">
+                    <label class="form-label">First Name</label>
+                    <input class="form-control" @bind="pet.Owner.FirstName" />
+                </div>
+                <div class="col-md-3">
+                    <label class="form-label">Last Name</label>
+                    <input class="form-control" @bind="pet.Owner.LastName" />
+                </div>
+                <div class="col-md-3">
+                    <label class="form-label">Phone</label>
+                    <input class="form-control" @bind="pet.Owner.Phone" />
+                </div>
+                <div class="col-md-3">
+                    <label class="form-label">Email</label>
+                    <input class="form-control" @bind="pet.Owner.Email" />
+                </div>
+            </div>
+
+            @if (!string.IsNullOrEmpty(saveMessage))
+            {
+                <div class="alert @(saveSuccess ? "alert-success" : "alert-danger") mt-2">@saveMessage</div>
+            }
+
+            <button class="btn btn-primary mt-2" @onclick="SaveChanges" disabled="@saving">
+                @(saving ? "Saving..." : "Save Changes")
+            </button>
+        </div>
+    </div>
+
+    <div class="card">
+        <div class="card-body">
+            <h5 class="card-title">Treatment Notes</h5>
+
+            <div class="row mb-3 g-2">
+                <div class="col-md-3">
+                    <input class="form-control" placeholder="Title *" @bind="noteTitle" />
+                </div>
+                <div class="col-md-4">
+                    <input class="form-control" placeholder="Description *" @bind="noteDescription" />
+                </div>
+                <div class="col-md-3">
+                    <input class="form-control" placeholder="Veterinarian" @bind="noteVet" />
+                </div>
+                <div class="col-md-2">
+                    <button class="btn btn-success w-100" @onclick="AddNote" disabled="@addingNote">Add Note</button>
+                </div>
+            </div>
+
+            @if (!string.IsNullOrEmpty(noteError))
+            {
+                <div class="alert alert-danger">@noteError</div>
+            }
+
+            @if (pet.TreatmentNotes.Any())
+            {
+                <table class="table table-sm">
+                    <thead>
+                        <tr>
+                            <th>Date</th>
+                            <th>Title</th>
+                            <th>Description</th>
+                            <th>Veterinarian</th>
+                        </tr>
+                    </thead>
+                    <tbody>
+                        @foreach (var note in pet.TreatmentNotes.OrderByDescending(n => n.CreatedAt))
+                        {
+                            <tr>
+                                <td>@note.CreatedAt.ToString("yyyy-MM-dd HH:mm")</td>
+                                <td>@note.Title</td>
+                                <td>@note.Description</td>
+                                <td>@note.Veterinarian</td>
+                            </tr>
+                        }
+                    </tbody>
+                </table>
+            }
+            else
+            {
+                <p class="text-muted">No treatment notes yet.</p>
+            }
+        </div>
+    </div>
+}
+
+@code {
+    [Parameter] public int Id { get; set; }
+
+    private Pet? pet;
+    private DateTime? petDob;
+    private bool loading = true;
+    private bool saving, saveSuccess;
+    private string saveMessage = "";
+
+    private string noteTitle = "", noteDescription = "", noteVet = "", noteError = "";
+    private bool addingNote;
+
+    protected override async Task OnInitializedAsync()
+    {
+        pet = await Db.Pets.Include(p => p.Owner).Include(p => p.TreatmentNotes)
+            .FirstOrDefaultAsync(p => p.Id == Id);
+        if (pet?.DateOfBirth != null)
+            petDob = pet.DateOfBirth.Value.ToDateTime(TimeOnly.MinValue);
+        loading = false;
+    }
+
+    private async Task SaveChanges()
+    {
+        saving = true;
+        saveMessage = "";
+        try
+        {
+            pet!.DateOfBirth = petDob.HasValue ? DateOnly.FromDateTime(petDob.Value) : null;
+            await Db.SaveChangesAsync();
+            saveMessage = "Saved successfully.";
+            saveSuccess = true;
+        }
+        catch (Exception ex)
+        {
+            saveMessage = $"Error: {ex.Message}";
+            saveSuccess = false;
+        }
+        finally { saving = false; }
+    }
+
+    private async Task AddNote()
+    {
+        noteError = "";
+        if (string.IsNullOrWhiteSpace(noteTitle) || string.IsNullOrWhiteSpace(noteDescription))
+        {
+            noteError = "Title and description are required.";
+            return;
+        }
+        addingNote = true;
+        try
+        {
+            var note = new TreatmentNote
+            {
+                Title = noteTitle,
+                Description = noteDescription,
+                Veterinarian = string.IsNullOrWhiteSpace(noteVet) ? null : noteVet,
+                PetId = pet!.Id,
+                CreatedAt = DateTime.UtcNow
+            };
+            Db.TreatmentNotes.Add(note);
+            await Db.SaveChangesAsync();
+            pet.TreatmentNotes.Add(note);
+            noteTitle = noteDescription = noteVet = "";
+        }
+        catch (Exception ex)
+        {
+            noteError = $"Error: {ex.Message}";
+        }
+        finally { addingNote = false; }
+    }
+}
+

