@@ -1,0 +1,312 @@
+@page "/appointments"
+@attribute [Authorize]
+@rendermode InteractiveServer
+@inject ApplicationDbContext Db
+
+<PageTitle>Appointments</PageTitle>
+
+<h2 class="mb-3">Appointments - Weekly View</h2>
+
+<div class="d-flex align-items-center mb-3 gap-2">
+    <button class="btn btn-outline-secondary" @onclick="PrevWeek">&laquo; Prev</button>
+    <button class="btn btn-outline-primary" @onclick="GoToday">Today</button>
+    <button class="btn btn-outline-secondary" @onclick="NextWeek">Next &raquo;</button>
+    <span class="ms-3 fw-bold">@weekStart.ToString("MMM dd") - @weekEnd.ToString("MMM dd, yyyy")</span>
+</div>
+
+@if (loading)
+{
+    <p><em>Loading...</em></p>
+}
+else
+{
+    <div class="table-responsive">
+        <table class="table table-bordered table-sm" style="font-size:0.8rem;">
+            <thead>
+                <tr>
+                    <th style="width:60px;">Time</th>
+                    @foreach (var day in days)
+                    {
+                        <th class="text-center">@day.ToString("ddd MM/dd")</th>
+                    }
+                </tr>
+            </thead>
+            <tbody>
+                @for (int slotIdx = 0; slotIdx < slots.Count; slotIdx++)
+                {
+                    var slot = slots[slotIdx];
+                    <tr>
+                        <td class="text-nowrap">@slot.ToString(@"hh\:mm")</td>
+                        @foreach (var day in days)
+                        {
+                            var slotTime = day.ToDateTime(TimeOnly.FromTimeSpan(slot));
+                            var appt = GetAppointment(slotTime);
+                            if (appt != null)
+                            {
+                                var bgClass = appt.Status switch
+                                {
+                                    AppointmentStatus.Scheduled => "bg-success text-white",
+                                    AppointmentStatus.Completed => "bg-secondary text-white",
+                                    AppointmentStatus.Cancelled => "bg-danger text-white",
+                                    _ => ""
+                                };
+                                <td class="@bgClass p-1" style="cursor:pointer;" @onclick="() => SelectAppointment(appt)">
+                                    <small>@appt.Pet.Name - @appt.Reason</small>
+                                </td>
+                            }
+                            else
+                            {
+                                <td class="p-1" style="cursor:pointer;" @onclick="() => SelectSlot(slotTime)">
+                                    &nbsp;
+                                </td>
+                            }
+                        }
+                    </tr>
+                }
+            </tbody>
+        </table>
+    </div>
+}
+
+@if (showCreateForm)
+{
+    <div class="card mt-3">
+        <div class="card-body">
+            <h5>New Appointment - @selectedSlotTime?.ToString("ddd MMM dd, hh:mm tt")</h5>
+            <div class="row g-2 mb-2">
+                <div class="col-md-4">
+                    <label class="form-label">Pet (search)</label>
+                    <input class="form-control" @bind="petSearch" @bind:event="oninput" @bind:after="SearchPets" placeholder="Type pet name..." />
+                    @if (matchingPets.Any())
+                    {
+                        <ul class="list-group mt-1" style="max-height:120px;overflow-y:auto;">
+                            @foreach (var p in matchingPets)
+                            {
+                                <li class="list-group-item list-group-item-action" style="cursor:pointer" @onclick="() => SelectPet(p)">
+                                    @p.Name (@p.Owner.FullName)
+                                </li>
+                            }
+                        </ul>
+                    }
+                    @if (selectedPet != null)
+                    {
+                        <small class="text-success">Selected: @selectedPet.Name</small>
+                    }
+                </div>
+                <div class="col-md-3">
+                    <label class="form-label">Reason</label>
+                    <input class="form-control" @bind="newReason" />
+                </div>
+                <div class="col-md-3">
+                    <label class="form-label">Veterinarian</label>
+                    <input class="form-control" @bind="newVet" />
+                </div>
+                <div class="col-md-2">
+                    <label class="form-label">Duration (min)</label>
+                    <input type="number" class="form-control" @bind="newDuration" />
+                </div>
+            </div>
+            @if (!string.IsNullOrEmpty(formError))
+            {
+                <div class="alert alert-danger">@formError</div>
+            }
+            <button class="btn btn-success me-2" @onclick="CreateAppointment" disabled="@saving">Create</button>
+            <button class="btn btn-secondary" @onclick="() => showCreateForm = false">Cancel</button>
+        </div>
+    </div>
+}
+
+@if (showEditForm && selectedAppointment != null)
+{
+    <div class="card mt-3">
+        <div class="card-body">
+            <h5>Appointment: @selectedAppointment.Pet.Name - @selectedAppointment.Reason</h5>
+            <p>
+                <strong>Time:</strong> @selectedAppointment.StartTime.ToString("ddd MMM dd, hh:mm tt") -
+                @selectedAppointment.EndTime.ToString("hh:mm tt")
+                | <strong>Status:</strong> @selectedAppointment.Status
+                | <strong>Vet:</strong> @selectedAppointment.Veterinarian
+            </p>
+            <div class="row g-2 mb-2">
+                <div class="col-md-4">
+                    <label class="form-label">Reschedule to</label>
+                    <input type="datetime-local" class="form-control" @bind="rescheduleTime" />
+                </div>
+            </div>
+            @if (!string.IsNullOrEmpty(editError))
+            {
+                <div class="alert alert-danger">@editError</div>
+            }
+            <button class="btn btn-primary me-2" @onclick="Reschedule" disabled="@saving">Reschedule</button>
+            @if (selectedAppointment.Status == AppointmentStatus.Scheduled)
+            {
+                <button class="btn btn-warning me-2" @onclick="CompleteAppointment">Complete</button>
+                <button class="btn btn-danger me-2" @onclick="CancelAppointment">Cancel Appointment</button>
+            }
+            <button class="btn btn-secondary" @onclick="() => showEditForm = false">Close</button>
+        </div>
+    </div>
+}
+
+@code {
+    private DateOnly weekStart;
+    private DateOnly weekEnd;
+    private List<DateOnly> days = new();
+    private List<TimeSpan> slots = new();
+    private List<Appointment> appointments = new();
+    private bool loading = true;
+
+    private bool showCreateForm, showEditForm, saving;
+    private DateTime? selectedSlotTime;
+    private Appointment? selectedAppointment;
+    private DateTime? rescheduleTime;
+
+    private string petSearch = "", newReason = "", newVet = "", formError = "", editError = "";
+    private int newDuration = 30;
+    private List<Pet> matchingPets = new();
+    private Pet? selectedPet;
+
+    protected override async Task OnInitializedAsync()
+    {
+        InitSlots();
+        SetWeek(DateOnly.FromDateTime(DateTime.Today));
+        await LoadAppointments();
+    }
+
+    private void InitSlots()
+    {
+        slots = new();
+        for (var t = new TimeSpan(8, 0, 0); t < new TimeSpan(18, 0, 0); t += TimeSpan.FromMinutes(30))
+            slots.Add(t);
+    }
+
+    private void SetWeek(DateOnly date)
+    {
+        var dow = date.DayOfWeek;
+        int diff = dow == DayOfWeek.Sunday ? -6 : (int)DayOfWeek.Monday - (int)dow;
+        weekStart = date.AddDays(diff);
+        weekEnd = weekStart.AddDays(5); // Mon-Sat
+        days = Enumerable.Range(0, 6).Select(i => weekStart.AddDays(i)).ToList();
+    }
+
+    private async Task LoadAppointments()
+    {
+        loading = true;
+        var start = weekStart.ToDateTime(TimeOnly.MinValue);
+        var end = weekEnd.AddDays(1).ToDateTime(TimeOnly.MinValue);
+        appointments = await Db.Appointments
+            .Include(a => a.Pet).ThenInclude(p => p.Owner)
+            .Where(a => a.StartTime >= start && a.StartTime < end)
+            .ToListAsync();
+        loading = false;
+    }
+
+    private Appointment? GetAppointment(DateTime slotTime)
+    {
+        return appointments.FirstOrDefault(a => a.StartTime <= slotTime && a.EndTime > slotTime);
+    }
+
+    private async Task PrevWeek() { SetWeek(weekStart.AddDays(-7)); await LoadAppointments(); }
+    private async Task NextWeek() { SetWeek(weekStart.AddDays(7)); await LoadAppointments(); }
+    private async Task GoToday() { SetWeek(DateOnly.FromDateTime(DateTime.Today)); await LoadAppointments(); }
+
+    private void SelectSlot(DateTime slotTime)
+    {
+        selectedSlotTime = slotTime;
+        showCreateForm = true;
+        showEditForm = false;
+        formError = "";
+        petSearch = "";
+        matchingPets = new();
+        selectedPet = null;
+        newReason = "";
+        newVet = "";
+        newDuration = 30;
+    }
+
+    private void SelectAppointment(Appointment appt)
+    {
+        selectedAppointment = appt;
+        rescheduleTime = appt.StartTime;
+        showEditForm = true;
+        showCreateForm = false;
+        editError = "";
+    }
+
+    private async Task SearchPets()
+    {
+        if (petSearch.Length < 2) { matchingPets = new(); return; }
+        var term = petSearch.ToLower();
+        matchingPets = await Db.Pets.Include(p => p.Owner)
+            .Where(p => p.Name.ToLower().Contains(term))
+            .Take(10).ToListAsync();
+    }
+
+    private void SelectPet(Pet p)
+    {
+        selectedPet = p;
+        matchingPets = new();
+        petSearch = p.Name;
+    }
+
+    private async Task CreateAppointment()
+    {
+        formError = "";
+        if (selectedPet == null) { formError = "Please select a pet."; return; }
+        if (string.IsNullOrWhiteSpace(newReason)) { formError = "Reason is required."; return; }
+        saving = true;
+        try
+        {
+            var appt = new Appointment
+            {
+                StartTime = selectedSlotTime!.Value,
+                EndTime = selectedSlotTime.Value.AddMinutes(newDuration),
+                Reason = newReason,
+                Veterinarian = string.IsNullOrWhiteSpace(newVet) ? null : newVet,
+                PetId = selectedPet.Id,
+                Status = AppointmentStatus.Scheduled
+            };
+            Db.Appointments.Add(appt);
+            await Db.SaveChangesAsync();
+            showCreateForm = false;
+            await LoadAppointments();
+        }
+        catch (Exception ex) { formError = $"Error: {ex.Message}"; }
+        finally { saving = false; }
+    }
+
+    private async Task Reschedule()
+    {
+        editError = "";
+        if (rescheduleTime == null) { editError = "Select a new time."; return; }
+        saving = true;
+        try
+        {
+            var duration = selectedAppointment!.EndTime - selectedAppointment.StartTime;
+            selectedAppointment.StartTime = rescheduleTime.Value;
+            selectedAppointment.EndTime = rescheduleTime.Value + duration;
+            await Db.SaveChangesAsync();
+            showEditForm = false;
+            await LoadAppointments();
+        }
+        catch (Exception ex) { editError = $"Error: {ex.Message}"; }
+        finally { saving = false; }
+    }
+
+    private async Task CancelAppointment()
+    {
+        selectedAppointment!.Status = AppointmentStatus.Cancelled;
+        await Db.SaveChangesAsync();
+        showEditForm = false;
+        await LoadAppointments();
+    }
+
+    private async Task CompleteAppointment()
+    {
+        selectedAppointment!.Status = AppointmentStatus.Completed;
+        await Db.SaveChangesAsync();
+        showEditForm = false;
+        await LoadAppointments();
+    }
+}
+

