+@page "/billing/{Id:int}"
+@attribute [Authorize]
+@rendermode InteractiveServer
+@inject ApplicationDbContext Db
+@inject NavigationManager Nav
+
+<PageTitle>Invoice Detail</PageTitle>
+
+@if (loading)
+{
+    <p><em>Loading...</em></p>
+}
+else if (invoice == null)
+{
+    <p class="text-danger">Invoice not found.</p>
+}
+else
+{
+    <h2 class="mb-3">Invoice @invoice.InvoiceNumber</h2>
+
+    <div class="row mb-3">
+        <div class="col-md-6">
+            <p><strong>Owner:</strong> @invoice.Owner.FullName</p>
+            <p><strong>Status:</strong> <span class="badge @GetStatusBadge(invoice.Status)">@invoice.Status</span></p>
+            <p><strong>Issued:</strong> @invoice.IssuedDate.ToString("yyyy-MM-dd")</p>
+            @if (invoice.DueDate.HasValue)
+            {
+                <p><strong>Due:</strong> @invoice.DueDate.Value.ToString("yyyy-MM-dd")</p>
+            }
+        </div>
+        <div class="col-md-6 text-end">
+            <h4>Total: @invoice.Total.ToString("C")</h4>
+            <p>Paid: @invoice.AmountPaid.ToString("C") | Balance: <strong>@invoice.Balance.ToString("C")</strong></p>
+            @if (invoice.Status == InvoiceStatus.Draft)
+            {
+                <button class="btn btn-primary" @onclick="IssueInvoice">Issue Invoice</button>
+            }
+        </div>
+    </div>
+
+    @if (!string.IsNullOrEmpty(message))
+    {
+        <div class="alert alert-success">@message</div>
+    }
+
+    <div class="card mb-4">
+        <div class="card-body">
+            <h5>Line Items</h5>
+            <table class="table table-sm">
+                <thead>
+                    <tr>
+                        <th>Description</th>
+                        <th>Qty</th>
+                        <th>Unit Price</th>
+                        <th>Amount</th>
+                        <th></th>
+                    </tr>
+                </thead>
+                <tbody>
+                    @foreach (var li in invoice.LineItems)
+                    {
+                        <tr>
+                            <td>@li.Description</td>
+                            <td>@li.Quantity</td>
+                            <td>@li.UnitPrice.ToString("C")</td>
+                            <td>@li.Amount.ToString("C")</td>
+                            <td>
+                                @if (invoice.Status == InvoiceStatus.Draft)
+                                {
+                                    <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveLineItem(li)">Remove</button>
+                                }
+                            </td>
+                        </tr>
+                    }
+                </tbody>
+            </table>
+
+            @if (invoice.Status == InvoiceStatus.Draft)
+            {
+                <div class="row g-2">
+                    <div class="col-md-5">
+                        <input class="form-control" placeholder="Description" @bind="newLineDesc" />
+                    </div>
+                    <div class="col-md-2">
+                        <input type="number" class="form-control" placeholder="Qty" @bind="newLineQty" min="1" />
+                    </div>
+                    <div class="col-md-3">
+                        <input type="number" step="0.01" class="form-control" placeholder="Unit Price" @bind="newLinePrice" />
+                    </div>
+                    <div class="col-md-2">
+                        <button class="btn btn-success w-100" @onclick="AddLineItem">Add</button>
+                    </div>
+                </div>
+                @if (!string.IsNullOrEmpty(lineError))
+                {
+                    <div class="alert alert-danger mt-2">@lineError</div>
+                }
+            }
+        </div>
+    </div>
+
+    <div class="card mb-4">
+        <div class="card-body">
+            <h5>Record Payment</h5>
+            <div class="row g-2 mb-2">
+                <div class="col-md-3">
+                    <input type="number" step="0.01" class="form-control" placeholder="Amount" @bind="payAmount" />
+                </div>
+                <div class="col-md-3">
+                    <select class="form-select" @bind="payMethod">
+                        @foreach (var m in Enum.GetValues<PaymentMethod>())
+                        {
+                            <option value="@m">@m</option>
+                        }
+                    </select>
+                </div>
+                <div class="col-md-4">
+                    <input class="form-control" placeholder="Reference" @bind="payReference" />
+                </div>
+                <div class="col-md-2">
+                    <button class="btn btn-primary w-100" @onclick="RecordPayment">Pay</button>
+                </div>
+            </div>
+            @if (!string.IsNullOrEmpty(payError))
+            {
+                <div class="alert alert-danger">@payError</div>
+            }
+
+            <h6 class="mt-3">Payment History</h6>
+            @if (invoice.Payments.Any())
+            {
+                <table class="table table-sm">
+                    <thead>
+                        <tr><th>Date</th><th>Amount</th><th>Method</th><th>Reference</th></tr>
+                    </thead>
+                    <tbody>
+                        @foreach (var pay in invoice.Payments.OrderByDescending(p => p.PaidAt))
+                        {
+                            <tr>
+                                <td>@pay.PaidAt.ToString("yyyy-MM-dd HH:mm")</td>
+                                <td>@pay.Amount.ToString("C")</td>
+                                <td>@pay.Method</td>
+                                <td>@pay.Reference</td>
+                            </tr>
+                        }
+                    </tbody>
+                </table>
+            }
+            else
+            {
+                <p class="text-muted">No payments recorded.</p>
+            }
+        </div>
+    </div>
+}
+
+@code {
+    [Parameter] public int Id { get; set; }
+
+    private Invoice? invoice;
+    private bool loading = true;
+    private string message = "";
+
+    private string newLineDesc = "", lineError = "";
+    private int newLineQty = 1;
+    private decimal newLinePrice;
+
+    private decimal payAmount;
+    private PaymentMethod payMethod = PaymentMethod.Cash;
+    private string payReference = "", payError = "";
+
+    protected override async Task OnInitializedAsync()
+    {
+        invoice = await Db.Invoices
+            .Include(i => i.Owner)
+            .Include(i => i.LineItems)
+            .Include(i => i.Payments)
+            .FirstOrDefaultAsync(i => i.Id == Id);
+        loading = false;
+    }
+
+    private async Task AddLineItem()
+    {
+        lineError = "";
+        if (string.IsNullOrWhiteSpace(newLineDesc)) { lineError = "Description required."; return; }
+        if (newLineQty < 1) { lineError = "Quantity must be at least 1."; return; }
+
+        var item = new InvoiceLineItem
+        {
+            Description = newLineDesc,
+            Quantity = newLineQty,
+            UnitPrice = newLinePrice,
+            InvoiceId = invoice!.Id
+        };
+        Db.InvoiceLineItems.Add(item);
+        await Db.SaveChangesAsync();
+        invoice.LineItems.Add(item);
+        newLineDesc = "";
+        newLineQty = 1;
+        newLinePrice = 0;
+    }
+
+    private async Task RemoveLineItem(InvoiceLineItem item)
+    {
+        Db.InvoiceLineItems.Remove(item);
+        await Db.SaveChangesAsync();
+        invoice!.LineItems.Remove(item);
+    }
+
+    private async Task IssueInvoice()
+    {
+        invoice!.Status = InvoiceStatus.Issued;
+        await Db.SaveChangesAsync();
+        message = "Invoice issued successfully.";
+    }
+
+    private async Task RecordPayment()
+    {
+        payError = "";
+        if (payAmount <= 0) { payError = "Amount must be greater than 0."; return; }
+
+        var payment = new Payment
+        {
+            Amount = payAmount,
+            Method = payMethod,
+            Reference = string.IsNullOrWhiteSpace(payReference) ? null : payReference,
+            InvoiceId = invoice!.Id,
+            PaidAt = DateTime.UtcNow
+        };
+        Db.Payments.Add(payment);
+
+        if (invoice.AmountPaid + payAmount >= invoice.Total)
+            invoice.Status = InvoiceStatus.Paid;
+
+        await Db.SaveChangesAsync();
+        invoice.Payments.Add(payment);
+        payAmount = 0;
+        payReference = "";
+        message = "Payment recorded.";
+    }
+
+    private string GetStatusBadge(InvoiceStatus s) => s switch
+    {
+        InvoiceStatus.Draft => "bg-secondary",
+        InvoiceStatus.Issued => "bg-primary",
+        InvoiceStatus.Paid => "bg-success",
+        InvoiceStatus.Overdue => "bg-danger",
+        _ => "bg-secondary"
+    };
+}
+

