+@page "/billing/create"
+@attribute [Authorize]
+@rendermode InteractiveServer
+@inject ApplicationDbContext Db
+@inject NavigationManager Nav
+
+<PageTitle>Create Invoice</PageTitle>
+
+<h2 class="mb-3">Create Invoice</h2>
+
+<div class="card">
+    <div class="card-body">
+        <div class="row g-3">
+            <div class="col-md-6">
+                <label class="form-label">Owner (search by name)</label>
+                <input class="form-control" @bind="ownerSearch" @bind:event="oninput" @bind:after="SearchOwners"
+                       placeholder="Type owner name..." />
+                @if (matchingOwners.Any())
+                {
+                    <ul class="list-group mt-1" style="max-height:150px;overflow-y:auto;">
+                        @foreach (var o in matchingOwners)
+                        {
+                            <li class="list-group-item list-group-item-action" style="cursor:pointer" @onclick="() => SelectOwner(o)">
+                                @o.FullName — @o.Email
+                            </li>
+                        }
+                    </ul>
+                }
+                @if (selectedOwner != null)
+                {
+                    <div class="alert alert-info mt-2 py-1">Selected: <strong>@selectedOwner.FullName</strong></div>
+                }
+            </div>
+
+            <div class="col-md-6">
+                <label class="form-label">Link to Appointment (optional)</label>
+                <select class="form-select" @bind="selectedAppointmentId" disabled="@(selectedOwner == null)">
+                    <option value="0">-- None --</option>
+                    @foreach (var a in ownerAppointments)
+                    {
+                        <option value="@a.Id">@a.StartTime.ToString("yyyy-MM-dd") - @a.Pet.Name - @a.Reason</option>
+                    }
+                </select>
+            </div>
+
+            <div class="col-md-4">
+                <label class="form-label">Due Date (optional)</label>
+                <input type="date" class="form-control" @bind="dueDate" />
+            </div>
+        </div>
+
+        @if (!string.IsNullOrEmpty(error))
+        {
+            <div class="alert alert-danger mt-3">@error</div>
+        }
+
+        <button class="btn btn-primary mt-3" @onclick="Save" disabled="@saving">
+            @(saving ? "Creating..." : "Create Invoice")
+        </button>
+    </div>
+</div>
+
+@code {
+    private string ownerSearch = "", error = "";
+    private List<Owner> matchingOwners = new();
+    private Owner? selectedOwner;
+    private List<Appointment> ownerAppointments = new();
+    private int selectedAppointmentId;
+    private DateTime? dueDate;
+    private bool saving;
+
+    private async Task SearchOwners()
+    {
+        if (ownerSearch.Length < 2) { matchingOwners = new(); return; }
+        var term = ownerSearch.ToLower();
+        matchingOwners = await Db.Owners
+            .Where(o => o.FirstName.ToLower().Contains(term) || o.LastName.ToLower().Contains(term))
+            .Take(10).ToListAsync();
+    }
+
+    private async Task SelectOwner(Owner o)
+    {
+        selectedOwner = o;
+        matchingOwners = new();
+        ownerSearch = o.FullName;
+        ownerAppointments = await Db.Appointments
+            .Include(a => a.Pet)
+            .Where(a => a.Pet.OwnerId == o.Id && a.Invoice == null)
+            .OrderByDescending(a => a.StartTime)
+            .Take(20).ToListAsync();
+    }
+
+    private async Task Save()
+    {
+        error = "";
+        if (selectedOwner == null) { error = "Please select an owner."; return; }
+
+        saving = true;
+        try
+        {
+            var count = await Db.Invoices.CountAsync();
+            var invoice = new Invoice
+            {
+                InvoiceNumber = $"INV-{(count + 1):D5}",
+                OwnerId = selectedOwner.Id,
+                IssuedDate = DateTime.UtcNow,
+                DueDate = dueDate,
+                Status = InvoiceStatus.Draft,
+                AppointmentId = selectedAppointmentId > 0 ? selectedAppointmentId : null
+            };
+            Db.Invoices.Add(invoice);
+            await Db.SaveChangesAsync();
+            Nav.NavigateTo($"/billing/{invoice.Id}");
+        }
+        catch (Exception ex) { error = $"Error: {ex.Message}"; }
+        finally { saving = false; }
+    }
+}
+

